import{_ as a,o as e,c as n,a4 as s}from"./chunks/framework._in6GHBg.js";const g=JSON.parse('{"title":"完形填空详解","description":"","frontmatter":{},"headers":[],"relativePath":"english/Eng-Learn-Detail-006-完形填空详解-V1.0-20260405.md","filePath":"english/Eng-Learn-Detail-006-完形填空详解-V1.0-20260405.md"}'),l={name:"english/Eng-Learn-Detail-006-完形填空详解-V1.0-20260405.md"};function i(r,t,d,o,p,h){return e(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="完形填空详解" tabindex="-1">完形填空详解 <a class="header-anchor" href="#完形填空详解" aria-label="Permalink to &quot;完形填空详解&quot;">​</a></h1><p><strong>上下文逻辑+词汇精准=高分</strong></p><hr><h2 id="一、本章地图" tabindex="-1">一、本章地图 <a class="header-anchor" href="#一、本章地图" aria-label="Permalink to &quot;一、本章地图&quot;">​</a></h2><h3 id="核心目标" tabindex="-1">核心目标 <a class="header-anchor" href="#核心目标" aria-label="Permalink to &quot;核心目标&quot;">​</a></h3><p>学完本章，你将：</p><ol><li>理解完形填空的命题逻辑</li><li>掌握上下文线索的寻找方法</li><li>提高词汇辨析能力</li><li>培养语篇整体意识</li></ol><h3 id="知识网络" tabindex="-1">知识网络 <a class="header-anchor" href="#知识网络" aria-label="Permalink to &quot;知识网络&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>完形填空</span></span>
<span class="line"><span>├── 命题特点</span></span>
<span class="line"><span>│   ├── 体裁（记叙文为主）</span></span>
<span class="line"><span>│   ├── 考点分布</span></span>
<span class="line"><span>│   └── 文章长度</span></span>
<span class="line"><span>├── 解题步骤</span></span>
<span class="line"><span>│   ├── 通读全文</span></span>
<span class="line"><span>│   ├── 逐空分析</span></span>
<span class="line"><span>│   └── 复读检查</span></span>
<span class="line"><span>├── 线索类型 ⭐</span></span>
<span class="line"><span>│   ├── 原词复现</span></span>
<span class="line"><span>│   ├── 同义/近义</span></span>
<span class="line"><span>│   ├── 反义对比</span></span>
<span class="line"><span>│   └── 逻辑关系</span></span>
<span class="line"><span>└── 词汇辨析</span></span>
<span class="line"><span>    ├── 动词辨析</span></span>
<span class="line"><span>    ├── 名词辨析</span></span>
<span class="line"><span>    └── 形容词辨析</span></span></code></pre></div><hr><h2 id="二、命题特点" tabindex="-1">二、命题特点 <a class="header-anchor" href="#二、命题特点" aria-label="Permalink to &quot;二、命题特点&quot;">​</a></h2><h3 id="_2-1-文章体裁" tabindex="-1">2.1 文章体裁 <a class="header-anchor" href="#_2-1-文章体裁" aria-label="Permalink to &quot;2.1 文章体裁&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">体裁</th><th style="text-align:center;">占比</th><th style="text-align:left;">特点</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>记叙文</strong></td><td style="text-align:center;">70%</td><td style="text-align:left;">有情节、有人物、有情感变化</td></tr><tr><td style="text-align:center;"><strong>夹叙夹议</strong></td><td style="text-align:center;">20%</td><td style="text-align:left;">记叙+感悟</td></tr><tr><td style="text-align:center;"><strong>说明文</strong></td><td style="text-align:center;">10%</td><td style="text-align:left;">介绍事物、现象</td></tr></tbody></table><h3 id="_2-2-考点分布" tabindex="-1">2.2 考点分布 <a class="header-anchor" href="#_2-2-考点分布" aria-label="Permalink to &quot;2.2 考点分布&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">考点</th><th style="text-align:center;">占比</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>动词/动词短语</strong></td><td style="text-align:center;">40%</td><td style="text-align:left;">take/bring/carry/get</td></tr><tr><td style="text-align:center;"><strong>名词</strong></td><td style="text-align:center;">20%</td><td style="text-align:left;">上下文语境选择</td></tr><tr><td style="text-align:center;"><strong>形容词/副词</strong></td><td style="text-align:center;">20%</td><td style="text-align:left;">情感态度词</td></tr><tr><td style="text-align:center;"><strong>连词/介词</strong></td><td style="text-align:center;">15%</td><td style="text-align:left;">逻辑关系</td></tr><tr><td style="text-align:center;"><strong>代词/其他</strong></td><td style="text-align:center;">5%</td><td style="text-align:left;"></td></tr></tbody></table><hr><h2 id="三、解题步骤-⭐" tabindex="-1">三、解题步骤 ⭐ <a class="header-anchor" href="#三、解题步骤-⭐" aria-label="Permalink to &quot;三、解题步骤 ⭐&quot;">​</a></h2><h3 id="step-1-通读全文-不看选项-2-3分钟" tabindex="-1">Step 1：通读全文（不看选项，2-3分钟） <a class="header-anchor" href="#step-1-通读全文-不看选项-2-3分钟" aria-label="Permalink to &quot;Step 1：通读全文（不看选项，2-3分钟）&quot;">​</a></h3><p><strong>目的</strong>：</p><ul><li>了解文章大意</li><li>把握文章基调（积极/消极）</li><li>了解人物、情节发展</li></ul><p><strong>注意</strong>：</p><ul><li>不要急着看选项</li><li>遇到空格先跳过</li><li>注意首尾段（往往点题）</li></ul><hr><h3 id="step-2-逐空分析-先易后难" tabindex="-1">Step 2：逐空分析（先易后难） <a class="header-anchor" href="#step-2-逐空分析-先易后难" aria-label="Permalink to &quot;Step 2：逐空分析（先易后难）&quot;">​</a></h3><p><strong>原则</strong>：</p><ul><li>简单题先做（有明显线索的）</li><li>难题标记后做（暂时不确定的）</li><li>不要在一道题上纠结太久</li></ul><hr><h3 id="step-3-复读检查-2-3分钟" tabindex="-1">Step 3：复读检查（2-3分钟） <a class="header-anchor" href="#step-3-复读检查-2-3分钟" aria-label="Permalink to &quot;Step 3：复读检查（2-3分钟）&quot;">​</a></h3><p><strong>检查内容</strong>：</p><ul><li>文章是否通顺</li><li>逻辑是否合理</li><li>时态是否一致</li><li>答案是否符合上下文</li></ul><hr><h2 id="四、线索类型-⭐" tabindex="-1">四、线索类型 ⭐ <a class="header-anchor" href="#四、线索类型-⭐" aria-label="Permalink to &quot;四、线索类型 ⭐&quot;">​</a></h2><h3 id="_4-1-原词复现" tabindex="-1">4.1 原词复现 <a class="header-anchor" href="#_4-1-原词复现" aria-label="Permalink to &quot;4.1 原词复现&quot;">​</a></h3><p><strong>原文中出现过的词再次出现</strong>。</p><p><strong>示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I had been driving for hours, feeling increasingly _____.</span></span>
<span class="line"><span>（后文）Finally, I realized I was suffering from _____.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>选项：A. angry  B. tired  C. excited  D. worried</span></span>
<span class="line"><span></span></span>
<span class="line"><span>分析：后文提到 suffering from，结合 driving for hours，应该是 tired（疲劳）。</span></span></code></pre></div><h3 id="_4-2-同义-近义词" tabindex="-1">4.2 同义/近义词 <a class="header-anchor" href="#_4-2-同义-近义词" aria-label="Permalink to &quot;4.2 同义/近义词&quot;">​</a></h3><p><strong>选项与原文某词是同义词</strong>。</p><p><strong>示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>The old man was very generous, always ready to help others.</span></span>
<span class="line"><span>He was known for his _____.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>选项：A. kindness  B. honesty  C. bravery  D. wisdom</span></span>
<span class="line"><span></span></span>
<span class="line"><span>分析：generous 和 help others 对应 kindness（善良）。</span></span></code></pre></div><h3 id="_4-3-反义对比" tabindex="-1">4.3 反义对比 <a class="header-anchor" href="#_4-3-反义对比" aria-label="Permalink to &quot;4.3 反义对比&quot;">​</a></h3><p><strong>通过转折词找到反义词线索</strong>。</p><p><strong>示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>At first, I thought the task was easy. _____, I found it quite difficult.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>选项：A. However  B. Therefore  C. Besides  D. Otherwise</span></span>
<span class="line"><span></span></span>
<span class="line"><span>分析：easy 和 difficult 是反义词，用 However（然而）转折。</span></span></code></pre></div><h3 id="_4-4-逻辑关系" tabindex="-1">4.4 逻辑关系 <a class="header-anchor" href="#_4-4-逻辑关系" aria-label="Permalink to &quot;4.4 逻辑关系&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">关系</th><th style="text-align:center;">标志词</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>因果</strong></td><td style="text-align:center;">because, so, therefore</td><td style="text-align:left;">He was ill, so he stayed at home.</td></tr><tr><td style="text-align:center;"><strong>转折</strong></td><td style="text-align:center;">but, however, yet</td><td style="text-align:left;">Poor but happy.</td></tr><tr><td style="text-align:center;"><strong>递进</strong></td><td style="text-align:center;">and, also, besides</td><td style="text-align:left;">He is smart and hardworking.</td></tr><tr><td style="text-align:center;"><strong>让步</strong></td><td style="text-align:center;">although, though</td><td style="text-align:left;">Although tired, he kept working.</td></tr><tr><td style="text-align:center;"><strong>条件</strong></td><td style="text-align:center;">if, unless</td><td style="text-align:left;">If it rains, we will stay home.</td></tr><tr><td style="text-align:center;"><strong>时间</strong></td><td style="text-align:center;">when, before, after</td><td style="text-align:left;">When I arrived, he had left.</td></tr></tbody></table><hr><h2 id="五、词汇辨析" tabindex="-1">五、词汇辨析 <a class="header-anchor" href="#五、词汇辨析" aria-label="Permalink to &quot;五、词汇辨析&quot;">​</a></h2><h3 id="_5-1-动词辨析-高频" tabindex="-1">5.1 动词辨析（高频） <a class="header-anchor" href="#_5-1-动词辨析-高频" aria-label="Permalink to &quot;5.1 动词辨析（高频）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">动词</th><th style="text-align:left;">含义侧重</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>take</strong></td><td style="text-align:left;">拿走，花费（时间）</td></tr><tr><td style="text-align:center;"><strong>bring</strong></td><td style="text-align:left;">带来</td></tr><tr><td style="text-align:center;"><strong>carry</strong></td><td style="text-align:left;">搬运，携带</td></tr><tr><td style="text-align:center;"><strong>get</strong></td><td style="text-align:left;">得到，变得</td></tr><tr><td style="text-align:center;"><strong>hold</strong></td><td style="text-align:left;">握住，举办</td></tr><tr><td style="text-align:center;"><strong>catch</strong></td><td style="text-align:left;">抓住，赶上</td></tr><tr><td style="text-align:center;"><strong>keep</strong></td><td style="text-align:left;">保持，保留</td></tr><tr><td style="text-align:center;"><strong>make</strong></td><td style="text-align:left;">制作，使</td></tr></tbody></table><h3 id="_5-2-情感态度词" tabindex="-1">5.2 情感态度词 <a class="header-anchor" href="#_5-2-情感态度词" aria-label="Permalink to &quot;5.2 情感态度词&quot;">​</a></h3><p><strong>积极</strong>：</p><ul><li>happy, excited, delighted, pleased, satisfied</li><li>confident, optimistic, hopeful</li><li>surprised, amazed, astonished</li></ul><p><strong>消极</strong>：</p><ul><li>sad, disappointed, frustrated, depressed</li><li>worried, anxious, nervous, afraid</li><li>angry, annoyed, irritated</li></ul><h3 id="_5-3-常见搭配" tabindex="-1">5.3 常见搭配 <a class="header-anchor" href="#_5-3-常见搭配" aria-label="Permalink to &quot;5.3 常见搭配&quot;">​</a></h3><p><strong>动词+介词</strong>：</p><ul><li>look after 照顾</li><li>look for 寻找</li><li>take care of 照顾</li><li>take part in 参加</li><li>pay attention to 注意</li></ul><p><strong>形容词+介词</strong>：</p><ul><li>be good at 擅长</li><li>be interested in 对...感兴趣</li><li>be proud of 为...骄傲</li><li>be afraid of 害怕</li><li>be satisfied with 对...满意</li></ul><hr><h2 id="六、解题技巧" tabindex="-1">六、解题技巧 <a class="header-anchor" href="#六、解题技巧" aria-label="Permalink to &quot;六、解题技巧&quot;">​</a></h2><h3 id="技巧1-首句不设空原则" tabindex="-1">技巧1：首句不设空原则 <a class="header-anchor" href="#技巧1-首句不设空原则" aria-label="Permalink to &quot;技巧1：首句不设空原则&quot;">​</a></h3><p>完形填空首句通常不设空，帮助理解文章主题。</p><h3 id="技巧2-瞻前顾后" tabindex="-1">技巧2：瞻前顾后 <a class="header-anchor" href="#技巧2-瞻前顾后" aria-label="Permalink to &quot;技巧2：瞻前顾后&quot;">​</a></h3><p>不要只看空格所在句，要看前后句甚至前后段。</p><h3 id="技巧3-注意情感线索" tabindex="-1">技巧3：注意情感线索 <a class="header-anchor" href="#技巧3-注意情感线索" aria-label="Permalink to &quot;技巧3：注意情感线索&quot;">​</a></h3><p>记叙文中人物的情感变化往往是解题关键。</p><h3 id="技巧4-复核答案" tabindex="-1">技巧4：复核答案 <a class="header-anchor" href="#技巧4-复核答案" aria-label="Permalink to &quot;技巧4：复核答案&quot;">​</a></h3><p>做完后通读一遍，检查逻辑是否通顺。</p><hr><h2 id="七、配套练习" tabindex="-1">七、配套练习 <a class="header-anchor" href="#七、配套练习" aria-label="Permalink to &quot;七、配套练习&quot;">​</a></h2><h3 id="练习1-根据上下文选答案" tabindex="-1">练习1：根据上下文选答案 <a class="header-anchor" href="#练习1-根据上下文选答案" aria-label="Permalink to &quot;练习1：根据上下文选答案&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I used to be very shy. I never dared to speak in public. One day, my teacher asked me to give a speech in class. I was so _____ that I wanted to refuse.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>选项：A. happy  B. nervous  C. angry  D. bored</span></span>
<span class="line"><span></span></span>
<span class="line"><span>答案：B（根据前文shy、never dared可知是紧张）</span></span></code></pre></div><h3 id="练习2-根据逻辑关系选答案" tabindex="-1">练习2：根据逻辑关系选答案 <a class="header-anchor" href="#练习2-根据逻辑关系选答案" aria-label="Permalink to &quot;练习2：根据逻辑关系选答案&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>He is very rich. _____, he is not happy.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>选项：A. However  B. Therefore  C. Besides  D. And</span></span>
<span class="line"><span></span></span>
<span class="line"><span>答案：A（rich和not happy是转折关系）</span></span></code></pre></div><hr><p><strong>文档编号</strong>: Eng-Learn-Detail-006<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,78)])])}const u=a(l,[["render",i]]);export{g as __pageData,u as default};
